// The dental-procedure safety cross-check dataset, loaded onto the curated-dataset
// framework (issue #704). Copies the contrast-safety.ts shape: import the envelope
// JSON (generated by scripts/gen-dental-safety.ts), validate it once with
// loadDataset(), and expose the DRUG entries (antiresorptive / anticoagulant concepts,
// matched by RxCUI ingredient + synonym) plus the cardiac condition-gate table (in
// `meta`) the cross-check consumes. Identity is the concept `key` token (fieldStrategy
// "key"). The registry lists this for the linter; lib/dental-safety.ts is the DOMAIN
// cross-check. Pure — no DB, no network.

import rawDental from "./data/dental-safety.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  DentalDrugEntry,
  DentalSafetyMeta,
  DentalConditionGate,
} from "@/scripts/gen-dental-safety";

export type {
  DentalDrugEntry,
  DentalSafetyMeta,
  DentalConditionGate,
  DentalDrugCategory,
} from "@/scripts/gen-dental-safety";

// The validated dataset (envelope + guarantees). Throws at module load if the
// committed JSON ever violates the contract — a loud, early failure.
export const dentalSafetyDataset = loadDataset<
  DentalDrugEntry,
  DentalSafetyMeta
>(rawDental);

// Identity strategy: the concept `key` token, case-folded. For the linter.
export const dentalKeyStrategy = fieldStrategy("key");

// The drug entries (concepts) + the cardiac condition-gate table (dataset meta) the
// cross-check consumes.
export const DENTAL_DRUG_ENTRIES: DentalDrugEntry[] =
  dentalSafetyDataset.entries;
export const DENTAL_CONDITION_GATES: DentalConditionGate[] = (
  dentalSafetyDataset.meta as DentalSafetyMeta
).conditionGates;
